var e=[{id:`L2_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`와아, 여기가 아빠 회사가 있는 도시지? 무지 크다~`,JPN:`わあ、ここがパパの会社がある街？　すっごく大き～い！`,ENG:`Wow, so this is the city where you work, Daddy? It's huge!`,TWN:`哇啊，這裡就是爸爸公司所在的城市嗎？好大啊～`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`아, 맞다!`,JPN:`あっ、そうだ！`,ENG:`Oh, right!`,TWN:`啊，對了！`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`아빠, 혼자 지내려니 심심하지?`,JPN:`パパ、一人だと退屈でしょ？`,ENG:`Daddy, doesn't it get boring staying by yourself here?`,TWN:`爸爸，一個人生活很無聊吧？`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`그럴까 봐 내가 아빠랑 함께할 사람들을 찾아다녔거든.`,JPN:`だから、パパと一緒に働く人たちを探しに行ってみたの。`,ENG:`That's why I've been looking for people who can stay by your side.`,TWN:`我怕爸爸無聊，所以找了一下能陪爸爸的人。`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`그러다가 부사장님 자리에서 이런 지원서를 찾았어.`,JPN:`そしたら、副社長の席でこんな申請書を見つけたんだ。`,ENG:`And then I came across this application at the Vice President's desk.`,TWN:`然後就在副總的位置上找到了這個申請書。`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_02`},{id:`L7_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`관리국이 만든 건데 컨소시엄이라고 부른다나 봐.`,JPN:`管理局が作ったんだけど、コンソーシアムって呼ぶみたい。`,ENG:`It's for something made by the Administration... I guess they call it a Consortium.`,TWN:`好像是管理局成立的，叫作公會的東西。`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`이걸 내면 다른 회사들이랑 친구가 될 수 있대!`,JPN:`これを出せば、他の会社とお友達になれるんだって！`,ENG:`You can make friends with other companies if you submit this!`,TWN:`上面說只要提交這個，就能跟其他公司成為朋友了！`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}},sfx:`FX_COMBAT_ALL_TECH_10`},{id:`L10_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`물론 아빠가 직접 컨소시엄을 세워서 사람들을 모으는 것도 가능해.`,JPN:`もちろん、パパが自分でコンソーシアムを作って人を集めることもできるよ。`,ENG:`You can even create your own Consortium and have other people join you.`,TWN:`當然，爸爸也可以自己成立公會並召集一群人。`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`어때? 굉장하지?`,JPN:`どう？　すごいでしょ？`,ENG:`What do you think? Isn't it amazing?`,TWN:`怎麼樣？很厲害吧？`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`어려운 일이 생겨도 멋진 친구들과 함께라면 쉽게 헤쳐 나갈 수 있을 거야.`,JPN:`大変なことが起きても、素敵な仲間と一緒ならきっと乗り越えられるはずだよ。`,ENG:`I'm sure you'll be able to overcome any difficulty if you have great friends to help you.`,TWN:`遇到困難的時候，跟帥氣的朋友們並肩作戰，可以輕鬆解決困難。`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`난 아빠가 친구들이랑 많이많이 친해져서, 오래오래 즐거운 시간을 보내면 좋겠어!`,JPN:`私、パパにはお友達と仲良くなって、ずーっと楽しい時間を過ごしてほしいの！`,ENG:`I hope you'll make lots of good friends and enjoy yourself!`,TWN:`我希望爸爸交很多很多朋友，永遠都開開心心的！`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`친구들을 사귀면 나한테 제일 먼저 소개시켜 줄 거지? 기대하고 있을게!`,JPN:`お友達ができたら、一番に私を紹介してくれるんでしょ？　楽しみにしてるね！`,ENG:`Please introduce me to your friends before anyone else, okay? I'm looking forward to it!`,TWN:`交到朋友後，一定要第一時間就介紹給我喔？我好期待喔！`},stage:{bg:`CITY_FLOAT`,bgm:`THMEA_HRTBERRY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};